\displaystyle{\begin{aligned}
   \frac{17}{18} - \frac{4}{9}
        \amp =  \frac{17}{18} - \frac{8}{18} \\
        \amp = \frac{17 - 8}{18} \\
        \amp = \frac{9}{18} \amp  \hbox{We can reduce this by dividing 9 into both the numerator and the denominator.
}\\
        \amp = \frac{1}{2}
\end{aligned}
    }
